import httpx
import os
import uuid


class AnthropicClient:
    """Minimal Anthropic API client with correct headers."""

    BASE = "https://api.anthropic.com"
    VERSION = "2023-06-01"

    def __init__(self, api_key: str | None = None, timeout: float = 60.0):
        self._key = api_key or os.environ["ANTHROPIC_API_KEY"]
        self._client = httpx.Client(
            base_url=self.BASE,
            headers=self._base_headers(),
            timeout=timeout,
        )

    def _base_headers(self) -> dict[str, str]:
        return {
            "Authorization": f"Bearer {self._key}",
            "anthropic-version": self.VERSION,
            "Content-Type": "application/json",
            "Accept": "application/json",
            "User-Agent": "MyAgent/1.0 (httpx)",
        }

    def _trace_headers(self, run_id: str | None = None) -> dict[str, str]:
        return {"X-Request-ID": run_id or str(uuid.uuid4())}

    def create_message(
        self,
        messages: list[dict],
        *,
        model: str = "claude-3-5-sonnet-20241022",
        max_tokens: int = 1024,
        system: str | None = None,
        run_id: str | None = None,
    ) -> dict:
        body: dict = {
            "model": model,
            "max_tokens": max_tokens,
            "messages": messages,
        }
        if system:
            body["system"] = system

        resp = self._client.post(
            "/v1/messages",
            json=body,  # sets Content-Type: application/json automatically
            headers=self._trace_headers(run_id),
        )

        # Read rate-limit headers before raising to enable proactive throttling
        remaining = resp.headers.get("x-ratelimit-remaining-requests")
        if remaining is not None and int(remaining) < 5:
            print(f"[warn] Only {remaining} requests remaining in rate-limit window")

        resp.raise_for_status()
        return resp.json()

    def list_documents(
        self, q: str = "", limit: int = 20, page: int = 1
    ) -> dict:
        resp = self._client.get(
            "/v1/documents",
            params={"q": q, "limit": limit, "page": page},
        )
        resp.raise_for_status()
        return resp.json()

import httpx
import json


def stream_message(api_key: str, messages: list[dict]) -> str:
    """Stream a completion and return the accumulated text."""
    headers = {
        "Authorization": f"Bearer {api_key}",
        "anthropic-version": "2023-06-01",
        "Content-Type": "application/json",
        "Accept": "text/event-stream",  # required for SSE
    }
    body = {
        "model": "claude-3-5-sonnet-20241022",
        "max_tokens": 1024,
        "messages": messages,
        "stream": True,
    }
    chunks = []
    with httpx.stream(
        "POST",
        "https://api.anthropic.com/v1/messages",
        headers=headers,
        json=body,
        timeout=120.0,
    ) as resp:
        resp.raise_for_status()
        for line in resp.iter_lines():
            if line.startswith("data:"):
                payload = json.loads(line[5:].strip())
                if payload.get("type") == "content_block_delta":
                    chunks.append(payload["delta"].get("text", ""))
    return "".join(chunks)

// Node.js — paginated document search with query params
async function searchDocuments(baseUrl, apiKey, query, { page = 1, limit = 20 } = {}) {
  const url = new URL("/v1/documents", baseUrl);
  url.searchParams.set("q", query);          // percent-encoded automatically
  url.searchParams.set("limit", String(limit));
  url.searchParams.set("page", String(page));

  const resp = await fetch(url.toString(), {
    method: "GET",
    headers: {
      Authorization: `Bearer ${apiKey}`,
      Accept: "application/json",
    },
  });

  if (!resp.ok) {
    const text = await resp.text();
    throw new Error(`API error ${resp.status}: ${text}`);
  }

  const contentType = resp.headers.get("content-type") ?? "";
  if (!contentType.includes("application/json")) {
    throw new Error(`Unexpected content-type: ${contentType}`);
  }

  return resp.json();
}

