import httpx

# WRONG — creates and closes a new connection on every call
def call_api(url, body, headers):
    return httpx.post(url, json=body, headers=headers).json()

# RIGHT — reuse the connection pool for the lifetime of the agent run
client = httpx.Client(base_url="https://api.anthropic.com", timeout=60.0)
def call_api(body, headers):
    return client.post("/v1/messages", json=body, headers=headers).json()

import httpx
import logging

logger = logging.getLogger("http")

def log_request(request: httpx.Request):
    # Redact Authorization before logging
    safe = {k: ("***" if k.lower() == "authorization" else v)
            for k, v in request.headers.items()}
    logger.debug("→ %s %s  headers=%s", request.method, request.url, safe)

def log_response(response: httpx.Response):
    logger.debug("← %s  ct=%s", response.status_code,
                 response.headers.get("content-type"))

client = httpx.Client(
    event_hooks={"request": [log_request], "response": [log_response]}
)
